"use client";

import { useEffect, useRef, useCallback, useMemo } from "react";

const hotCards = [
  { name: "玩偶姐姐", img: "/images/01/Snipaste_2026-01-13_20-35-33.png" },
  { name: "饼干姐姐", img: "/images/01/Snipaste_2026-01-13_20-44-06.png" },
  { name: "狐不妖", img: "/images/01/Snipaste_2026-01-13_21-15-21.png" },
];

const CARD_W = 140;
const CARD_H_LARGE = 220;
const CARD_GAP = 12;
const AUTO_PLAY_MS = 2000;
const TRANSITION_MS = 400;
const SCALE_ACTIVE = 1.1;
const SCALE_INACTIVE = 0.9;
const COPIES = 5;

export default function HeroSection() {
  const loopCards = useMemo(() => {
    const arr = [];
    for (let c = 0; c < COPIES; c++) {
      for (let i = 0; i < hotCards.length; i++) {
        arr.push({ ...hotCards[i], originalIndex: i });
      }
    }
    return arr;
  }, []);

  const total = loopCards.length;
  const middleStart = Math.floor(COPIES / 2) * hotCards.length;

  const containerRef = useRef<HTMLDivElement>(null);
  const trackRef = useRef<HTMLDivElement>(null);
  const activeIndex = useRef(middleStart);
  const autoPlayRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Drag state
  const dragStartX = useRef(0);
  const dragDelta = useRef(0);
  const isDragging = useRef(false);

  const getTranslateForIndex = useCallback(
    (index: number, containerWidth: number) => {
      const cardCenter = index * (CARD_W + CARD_GAP) + CARD_W / 2;
      return containerWidth / 2 - cardCenter;
    },
    []
  );

  const applyCardStyles = useCallback(
    (index: number, animate: boolean) => {
      const track = trackRef.current;
      if (!track) return;
      const cards = track.children;
      for (let i = 0; i < cards.length; i++) {
        const card = cards[i] as HTMLElement;
        const isCenter = i === index;
        card.style.transition = animate
          ? `transform ${TRANSITION_MS}ms cubic-bezier(0.25,0.1,0.25,1), opacity ${TRANSITION_MS}ms ease, box-shadow ${TRANSITION_MS}ms ease`
          : "none";
        card.style.transform = `scale(${isCenter ? SCALE_ACTIVE : SCALE_INACTIVE})`;
        card.style.opacity = isCenter ? "1" : "0.5";
        card.style.boxShadow = isCenter ? "0 0 24px 2px #FF2D7855" : "none";
      }
    },
    []
  );

  const applyLayout = useCallback(
    (index: number, animate: boolean) => {
      const container = containerRef.current;
      const track = trackRef.current;
      if (!container || !track) return;

      const tx = getTranslateForIndex(index, container.offsetWidth);
      track.style.transition = animate
        ? `transform ${TRANSITION_MS}ms cubic-bezier(0.25,0.1,0.25,1)`
        : "none";
      track.style.transform = `translateX(${tx}px)`;
      applyCardStyles(index, animate);
    },
    [getTranslateForIndex, applyCardStyles]
  );

  const resetToMiddle = useCallback(() => {
    const idx = activeIndex.current;
    const posInOriginal = ((idx % hotCards.length) + hotCards.length) % hotCards.length;
    const middleEquivalent = middleStart + posInOriginal;
    if (idx !== middleEquivalent) {
      activeIndex.current = middleEquivalent;
      applyLayout(middleEquivalent, false);
    }
  }, [middleStart, applyLayout]);

  const handleTransitionEnd = useCallback(
    (e: React.TransitionEvent) => {
      // Only react to the track's own transition, not children bubbling up
      if (e.target !== trackRef.current) return;
      resetToMiddle();
    },
    [resetToMiddle]
  );

  const goTo = useCallback(
    (index: number) => {
      activeIndex.current = index;
      applyLayout(index, true);
    },
    [applyLayout]
  );

  const advance = useCallback(() => {
    goTo(activeIndex.current + 1);
  }, [goTo]);

  // Initial layout
  useEffect(() => {
    applyLayout(activeIndex.current, false);
  }, [applyLayout]);

  // Auto-play
  useEffect(() => {
    autoPlayRef.current = setInterval(advance, AUTO_PLAY_MS);
    return () => {
      if (autoPlayRef.current) clearInterval(autoPlayRef.current);
    };
  }, [advance]);

  const pauseAutoPlay = useCallback(() => {
    if (autoPlayRef.current) {
      clearInterval(autoPlayRef.current);
      autoPlayRef.current = null;
    }
  }, []);

  const resumeAutoPlay = useCallback(() => {
    pauseAutoPlay();
    autoPlayRef.current = setInterval(advance, AUTO_PLAY_MS);
  }, [advance, pauseAutoPlay]);

  // --- Unified drag logic ---
  const startDrag = useCallback(
    (clientX: number) => {
      pauseAutoPlay();
      isDragging.current = true;
      dragStartX.current = clientX;
      dragDelta.current = 0;
      // Kill any ongoing transition so drag feels instant
      const track = trackRef.current;
      if (track) {
        const computed = getComputedStyle(track);
        const matrix = new DOMMatrix(computed.transform);
        track.style.transition = "none";
        track.style.transform = `translateX(${matrix.m41}px)`;
      }
    },
    [pauseAutoPlay]
  );

  const moveDrag = useCallback(
    (clientX: number) => {
      if (!isDragging.current) return;
      const container = containerRef.current;
      const track = trackRef.current;
      if (!container || !track) return;

      dragDelta.current = clientX - dragStartX.current;
      const baseTx = getTranslateForIndex(activeIndex.current, container.offsetWidth);
      track.style.transition = "none";
      track.style.transform = `translateX(${baseTx + dragDelta.current}px)`;

      // Dynamically update which card appears closest to center
      const currentTx = baseTx + dragDelta.current;
      const centerX = container.offsetWidth / 2;
      let closestIdx = activeIndex.current;
      let closestDist = Infinity;
      for (let i = 0; i < total; i++) {
        const cardCenterX = currentTx + i * (CARD_W + CARD_GAP) + CARD_W / 2;
        const dist = Math.abs(cardCenterX - centerX);
        if (dist < closestDist) {
          closestDist = dist;
          closestIdx = i;
        }
      }
      applyCardStyles(closestIdx, false);
    },
    [getTranslateForIndex, applyCardStyles, total]
  );

  const endDrag = useCallback(() => {
    if (!isDragging.current) return;
    isDragging.current = false;

    const delta = dragDelta.current;
    const threshold = CARD_W / 3;

    let newIndex = activeIndex.current;
    if (delta < -threshold) {
      newIndex += 1;
    } else if (delta > threshold) {
      newIndex -= 1;
    }
    newIndex = Math.max(0, Math.min(total - 1, newIndex));
    goTo(newIndex);
    resumeAutoPlay();
  }, [goTo, resumeAutoPlay, total]);

  // --- Touch events ---
  const onTouchStart = useCallback(
    (e: React.TouchEvent) => startDrag(e.touches[0].clientX),
    [startDrag]
  );
  const onTouchMove = useCallback(
    (e: React.TouchEvent) => moveDrag(e.touches[0].clientX),
    [moveDrag]
  );
  const onTouchEnd = useCallback(() => endDrag(), [endDrag]);

  // --- Mouse events (mousedown on container, move/up on document) ---
  const onMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault(); // prevent text selection
      startDrag(e.clientX);
    },
    [startDrag]
  );

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => moveDrag(e.clientX);
    const handleMouseUp = () => endDrag();

    document.addEventListener("mousemove", handleMouseMove);
    document.addEventListener("mouseup", handleMouseUp);
    return () => {
      document.removeEventListener("mousemove", handleMouseMove);
      document.removeEventListener("mouseup", handleMouseUp);
    };
  }, [moveDrag, endDrag]);

  return (
    <section className="flex flex-col w-full bg-[var(--color-bg-primary)]">
      {/* Hero Image Area */}
      <div className="relative w-full h-[560px] overflow-hidden">
        <div
          className="absolute inset-0 bg-cover bg-center"
          style={{ backgroundImage: "url('/images/hero-bg.jpg')" }}
        />
        <div className="absolute top-0 left-0 w-full h-[56px] flex items-center px-6 bg-[#0A0A0F80] z-10">
          <span className="text-[22px] font-bold text-[var(--color-text-primary)] tracking-[2px]">
            FANSONE
          </span>
        </div>
        <div
          className="absolute inset-0 flex flex-col justify-end gap-[6px] px-6 pb-10"
          style={{
            background:
              "linear-gradient(to top, #0A0A0F 0%, #0A0A0FDD 30%, #0A0A0F00 65%, #0A0A0F00 100%)",
          }}
        >
          <h1 className="text-[32px] font-black text-[var(--color-text-primary)]">
            全球美女网黄全收集
          </h1>
          <p className="text-[16px] font-medium text-[var(--color-text-secondary)]">
            网黄动态实时同步更新
          </p>
          <button className="mt-2 self-start rounded-full bg-[var(--color-accent)] px-10 py-[14px] text-[18px] font-bold text-white shadow-[0_0_24px_4px_#FF2D7860]">
            立即体验
          </button>
        </div>
      </div>

      {/* 热门网黄 Section */}
      <div className="flex flex-col gap-4 pt-6 w-full">
        <div className="flex items-center gap-2 px-6">
          <div className="w-1 h-5 rounded-sm bg-[var(--color-accent)]" />
          <span className="text-[20px] font-bold text-[var(--color-text-primary)]">
            热门网黄
          </span>
        </div>

        {/* Carousel */}
        <div
          ref={containerRef}
          className="relative w-full h-[300px] overflow-x-clip overflow-y-visible pt-[40px] select-none cursor-grab active:cursor-grabbing"
          onTouchStart={onTouchStart}
          onTouchMove={onTouchMove}
          onTouchEnd={onTouchEnd}
          onMouseDown={onMouseDown}
        >
          <div
            ref={trackRef}
            className="flex items-center absolute top-0 bottom-0 overflow-visible"
            style={{ gap: `${CARD_GAP}px`, paddingTop: 40 }}
            onTransitionEnd={handleTransitionEnd}
          >
            {loopCards.map((card, i) => (
              <div
                key={i}
                className="flex-shrink-0 flex flex-col items-center gap-2 rounded-2xl bg-[var(--color-bg-card)] p-2 pb-3 border border-[var(--color-accent-border)] pointer-events-none"
                style={{
                  width: CARD_W,
                  transformOrigin: "center bottom",
                }}
              >
                <div
                  className="w-full rounded-xl bg-cover bg-center"
                  style={{
                    backgroundImage: `url('${card.img}')`,
                    height: CARD_H_LARGE,
                  }}
                />
                <span className="text-[13px] font-semibold text-[var(--color-text-primary)]">
                  {card.name}
                </span>
              </div>
            ))}
          </div>

          {/* Fade edges */}
          <div className="absolute left-0 top-0 w-[60px] h-full bg-gradient-to-r from-[#0A0A0F] to-transparent pointer-events-none z-10" />
          <div className="absolute right-0 top-0 w-[40px] h-full bg-gradient-to-l from-[#0A0A0F] to-transparent pointer-events-none z-10" />
        </div>
      </div>
    </section>
  );
}
